# crop_venue_shots.sh
# Center-crop one or more venue images to exact 16:9 (1536×864) for use as
# blank-slate before-plates in the venue visualizer.
#
# Usage:
#   bash crop_venue_shots.sh input1.jpg [input2.jpg ...] [-o output_dir]
#
# Output files are named blank1.png, blank2.png, … in output_dir (default: .)
# Requires: ffmpeg (available in the Hyperagent sandbox).

set -e
OUTPUT_DIR="."
INPUTS=()

while [[ $# -gt 0 ]]; do
  case "$1" in
    -o|--output) OUTPUT_DIR="$2"; shift 2 ;;
    *) INPUTS+=("$1"); shift ;;
  esac
done

if [[ ${#INPUTS[@]} -eq 0 ]]; then
  echo "Usage: $0 input1.jpg [input2.jpg ...] [-o output_dir]"; exit 1
fi

mkdir -p "$OUTPUT_DIR"
IDX=1
for SRC in "${INPUTS[@]}"; do
  OUT="$OUTPUT_DIR/blank${IDX}.png"
  echo "Cropping $SRC → $OUT"
  ffmpeg -y -i "$SRC" \
    -vf "crop=iw:trunc(iw*9/16/2)*2,scale=1536:864" \
    "$OUT" 2>/dev/null
  IDX=$((IDX+1))
done
echo "Done. Cropped ${#INPUTS[@]} file(s) to $OUTPUT_DIR"
