"""
generate_visualizer.py
Generates a self-contained venue-visualizer HTML page — three 16:9 shots
each with a crossfade toggle between the empty venue and the brand-activated version.

Usage:
  python3 generate_visualizer.py \
    --blank   URL1 URL2 URL3 \
    --act     URL1 URL2 URL3 \
    --brand   "AIRSPACE" \
    --venue   "1 Hotel West Hollywood" \
    --labels  "Arrival Lobby" "The Courtyard" "The Entrance" \
    --captions "Becomes the brand booth" "Becomes the Build Bar" "Becomes Registration" \
    --accent1 "#b9ee46" \
    --accent2 "#bcaaff" \
    --accent3 "#8fd2ff" \
    --font    "Pixelify Sans" \
    --output  visualizer.html

Defaults: accents are lime/lavender/sky, font is Pixelify Sans, output is visualizer.html.
All --labels and --captions take exactly 3 values (one per shot).
"""

import argparse, sys

def build_html(brand, venue, font, acc, blanks, acts, labels, captions):
    font_url = f"https://fonts.googleapis.com/css2?family={font.replace(' ', '+')}:wght@500;600;700&family=Inter:wght@400;500;600&family=Share+Tech+Mono&display=swap"

    shots_html = ""
    for i, (bl, ac, lb, cap) in enumerate(zip(blanks, acts, labels, captions), 1):
        shots_html += f"""
    <div class="shot">
      <div class="label"><span class="num">0{i}</span><h2>{lb}</h2><span class="state">Empty venue</span></div>
      <div class="viz" data-on="false">
        <img class="base" src="{bl}" alt="{lb} — empty">
        <img class="act"  src="{ac}" alt="{lb} — activated">
        <button class="toggle"><span class="sw"></span><span class="tl">Activate {brand}</span></button>
      </div>
      <div class="cap">{cap}</div>
    </div>"""

    return f"""<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>{brand} — Venue Visualizer</title>
<link rel="preconnect" href="https://fonts.googleapis.com">
<link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
<link href="{font_url}" rel="stylesheet">
<style>
*{{box-sizing:border-box;margin:0;padding:0}}
:root{{--ink:#16181d;--soft:#6a6f79;--paper:#f3f2ee;--line:#e2e0d8;
      --a1:{acc[0]};--a2:{acc[1]};--a3:{acc[2]}}}
body{{background:var(--paper);color:var(--ink);font-family:'Inter',sans-serif;-webkit-font-smoothing:antialiased;line-height:1.55}}
.wrap{{max-width:1180px;margin:0 auto;padding:0 5vw}}
header{{padding:min(8vh,72px) 5vw 14px;text-align:center}}
.eyebrow{{font-family:'Share Tech Mono',monospace;font-size:.72rem;letter-spacing:.32em;text-transform:uppercase;color:var(--soft)}}
h1{{font-family:'{font}',monospace;font-weight:700;font-size:clamp(3rem,11vw,7rem);line-height:.9;letter-spacing:.02em;margin:14px 0 6px}}
.accents{{display:inline-flex;gap:7px;margin:6px 0 16px}}
.accents i{{width:14px;height:14px;display:block;border-radius:2px}}
.accents .a1{{background:var(--a1)}}.accents .a2{{background:var(--a2)}}.accents .a3{{background:var(--a3)}}
.lede{{font-size:1.04rem;color:var(--soft);max-width:560px;margin:0 auto}}
.allbtn{{margin-top:24px;display:inline-flex;align-items:center;gap:10px;cursor:pointer;
  border:1px solid var(--ink);background:var(--ink);color:var(--paper);
  font-family:'Share Tech Mono',monospace;font-size:.74rem;letter-spacing:.14em;
  text-transform:uppercase;padding:13px 24px;border-radius:50px;transition:.2s}}
.allbtn:hover{{transform:translateY(-1px)}}
.allbtn .d{{width:8px;height:8px;border-radius:50%;background:var(--a1);box-shadow:0 0 0 3px color-mix(in srgb,var(--a1) 30%,transparent)}}
.shots{{padding:34px 0 90px;display:flex;flex-direction:column;gap:clamp(44px,7vh,86px)}}
.shot .label{{display:flex;align-items:baseline;gap:14px;margin-bottom:14px}}
.shot .num{{font-family:'Share Tech Mono',monospace;font-size:.78rem;color:var(--soft);letter-spacing:.1em}}
.shot h2{{font-family:'{font}',monospace;font-weight:600;font-size:clamp(1.4rem,3vw,2.1rem)}}
.shot .state{{margin-left:auto;font-family:'Share Tech Mono',monospace;font-size:.66rem;letter-spacing:.16em;
  text-transform:uppercase;color:var(--soft);border:1px solid var(--line);border-radius:40px;padding:6px 13px;transition:.3s;white-space:nowrap}}
.viz{{position:relative;width:100%;aspect-ratio:16/9;border-radius:12px;overflow:hidden;cursor:pointer;
  background:#000;box-shadow:0 30px 70px -38px rgba(22,24,29,.5);outline:0 solid rgba(143,210,255,0);transition:outline .4s,box-shadow .4s}}
.viz img{{position:absolute;inset:0;width:100%;height:100%;object-fit:cover;display:block;user-select:none}}
.viz .act{{opacity:0;transition:opacity .8s ease}}
.viz.on .act{{opacity:1}}
.viz.on{{outline:3px solid color-mix(in srgb,var(--a3) 55%,transparent);box-shadow:0 36px 90px -36px color-mix(in srgb,var(--a3) 45%,transparent)}}
.toggle{{position:absolute;left:50%;bottom:20px;transform:translateX(-50%);z-index:5;display:inline-flex;align-items:center;gap:11px;
  cursor:pointer;border:none;background:rgba(243,242,238,.94);color:var(--ink);font-family:'Share Tech Mono',monospace;
  font-size:.74rem;letter-spacing:.13em;text-transform:uppercase;padding:13px 22px;border-radius:50px;
  box-shadow:0 10px 30px -8px rgba(0,0,0,.45);backdrop-filter:blur(6px);transition:.25s;white-space:nowrap}}
.toggle:hover{{transform:translateX(-50%) translateY(-2px)}}
.sw{{position:relative;width:34px;height:18px;border-radius:20px;background:#c7c5bd;transition:.3s;flex:0 0 auto}}
.sw::after{{content:"";position:absolute;top:2px;left:2px;width:14px;height:14px;border-radius:50%;background:#fff;transition:.3s}}
.toggle.on .sw{{background:var(--a1)}}.toggle.on .sw::after{{transform:translateX(16px)}}
.cap{{margin-top:14px;font-size:.92rem;color:var(--soft)}}
footer{{border-top:1px solid var(--line);padding:30px 5vw;text-align:center;font-family:'Share Tech Mono',monospace;
  font-size:.66rem;letter-spacing:.2em;color:var(--soft);text-transform:uppercase}}
@media(max-width:600px){{.toggle{{font-size:.66rem;padding:11px 16px}}}}
</style>
</head>
<body>
<header>
  <div class="eyebrow">Venue Visualizer &middot; {venue}</div>
  <h1>{brand}</h1>
  <div class="accents"><i class="a1"></i><i class="a2"></i><i class="a3"></i></div>
  <p class="lede">The space as it is — and brought to life with the brand. Toggle each shot on and off.</p>
  <button class="allbtn" id="allBtn"><span class="d"></span><span id="allLabel">Activate all</span></button>
</header>
<div class="wrap">
  <div class="shots">{shots_html}
  </div>
</div>
<footer>{venue} &nbsp;&middot;&nbsp; {brand} venue visualizer</footer>
<script>
function setShot(shot,on){{
  var viz=shot.querySelector('.viz'),tog=shot.querySelector('.toggle'),
      tl=shot.querySelector('.tl'),state=shot.querySelector('.state');
  viz.classList.toggle('on',on);viz.dataset.on=on;
  tog.classList.toggle('on',on);
  tl.textContent=on?'Show empty venue':'Activate {brand}';
  state.textContent=on?'{brand} activated':'Empty venue';
  state.style.color=on?'#16181d':'';
  state.style.borderColor=on?'var(--a3)':'';
}}
document.querySelectorAll('.shot').forEach(function(shot){{
  var viz=shot.querySelector('.viz');
  viz.addEventListener('click',function(e){{e.preventDefault();e.stopPropagation();setShot(shot,viz.dataset.on!=='true');}});
}});
var allOn=false;
document.getElementById('allBtn').addEventListener('click',function(){{
  allOn=!allOn;
  document.querySelectorAll('.shot').forEach(function(s){{setShot(s,allOn);}});
  document.getElementById('allLabel').textContent=allOn?'Reset all':'Activate all';
}});
</script>
</body>
</html>"""


def main():
    p = argparse.ArgumentParser(description="Generate venue visualizer HTML")
    p.add_argument("--blank",    nargs=3, required=True, metavar="URL", help="3 blank venue image URLs")
    p.add_argument("--act",      nargs=3, required=True, metavar="URL", help="3 activated image URLs")
    p.add_argument("--brand",    default="BRAND",                       help="Brand / event name (e.g. AIRSPACE)")
    p.add_argument("--venue",    default="Venue Name",                  help="Venue name for footer")
    p.add_argument("--labels",   nargs=3, default=["Shot 1","Shot 2","Shot 3"], help="3 shot labels")
    p.add_argument("--captions", nargs=3, default=["","",""],           help="3 one-line captions beneath shots")
    p.add_argument("--accent1",  default="#b9ee46",                     help="Primary accent color (hex)")
    p.add_argument("--accent2",  default="#bcaaff",                     help="Secondary accent color (hex)")
    p.add_argument("--accent3",  default="#8fd2ff",                     help="Tertiary accent color (hex)")
    p.add_argument("--font",     default="Pixelify Sans",               help="Google Font family for brand headline")
    p.add_argument("--output",   default="visualizer.html",             help="Output HTML file path")
    args = p.parse_args()

    html = build_html(
        brand=args.brand, venue=args.venue, font=args.font,
        acc=[args.accent1, args.accent2, args.accent3],
        blanks=args.blank, acts=args.act,
        labels=args.labels, captions=args.captions
    )
    with open(args.output, "w", encoding="utf-8") as f:
        f.write(html)
    print(f"Written: {args.output}  ({len(html):,} bytes)")
    print(f"Now run: PublishWebpage(filePath='{args.output}', title='{args.brand} — Venue Visualizer')")


if __name__ == "__main__":
    main()
